import React, { useState, useRef, useEffect } from 'react';
import './GeneratedComponent.css';

interface GeneratedComponentProps {
  id: string;
  code: string;
  position: { x: number; y: number };
  isSelected: boolean;
  onSelect: (id: string) => void;
  onResize: (id: string, width: number, height: number) => void;
  onMove: (id: string, x: number, y: number) => void;
  onEdit?: (id: string) => void;
  onDelete?: (id: string) => void;
  onDuplicate?: (id: string) => void;
}

const GeneratedComponent: React.FC<GeneratedComponentProps> = ({
  id,
  code,
  position,
  isSelected,
  onSelect,
  onResize,
  onMove,
  onEdit,
  onDelete,
  onDuplicate
}) => {
  const [size, setSize] = useState({ width: 300, height: 200 });
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [showContextMenu, setShowContextMenu] = useState(false);
  const [contextMenuPosition, setContextMenuPosition] = useState({ x: 0, y: 0 });
  const componentRef = useRef<HTMLDivElement>(null);
  const dragStart = useRef({ x: 0, y: 0 });

  // Handle component selection
  const handleMouseDown = (e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(id);

    if (e.target === componentRef.current) {
      setIsDragging(true);
      dragStart.current = { 
        x: e.clientX - position.x, 
        y: e.clientY - position.y 
      };
    }
  };

  // Handle dragging
  const handleMouseMove = (e: MouseEvent) => {
    if (isDragging) {
      const newX = e.clientX - dragStart.current.x;
      const newY = e.clientY - dragStart.current.y;
      onMove(id, newX, newY);
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
    setIsResizing(false);
  };

  // Handle resize
  const handleResizeStart = (e: React.MouseEvent, direction: string) => {
    e.stopPropagation();
    setIsResizing(true);
    // Implement resize logic based on direction
  };

  useEffect(() => {
    if (isDragging || isResizing) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);

      return () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
      };
    }
  }, [isDragging, isResizing]);

  // Render the AI-generated code safely
  const renderGeneratedContent = () => {
    try {
      // For now, we'll render HTML content
      // In a real implementation, you'd want to sanitize this content
      return (
        <div 
          className="generated-content"
          dangerouslySetInnerHTML={{ __html: code }}
        />
      );
    } catch (error) {
      return (
        <div className="error-content">
          <p>Error rendering component</p>
        </div>
      );
    }
  };

  return (
    <div
      ref={componentRef}
      className={`generated-component ${isSelected ? 'selected' : ''}`}
      style={{
        left: position.x,
        top: position.y,
        width: size.width,
        height: size.height,
      }}
      onMouseDown={handleMouseDown}
    >
      {/* Rendered Content */}
      <div className="component-content">
        {renderGeneratedContent()}
      </div>

      {/* Selection Handles */}
      {isSelected && (
        <div className="selection-handles">
          <div className="handle top-left" onMouseDown={(e) => handleResizeStart(e, 'tl')} />
          <div className="handle top-right" onMouseDown={(e) => handleResizeStart(e, 'tr')} />
          <div className="handle bottom-left" onMouseDown={(e) => handleResizeStart(e, 'bl')} />
          <div className="handle bottom-right" onMouseDown={(e) => handleResizeStart(e, 'br')} />
          <div className="handle top-center" onMouseDown={(e) => handleResizeStart(e, 't')} />
          <div className="handle bottom-center" onMouseDown={(e) => handleResizeStart(e, 'b')} />
          <div className="handle middle-left" onMouseDown={(e) => handleResizeStart(e, 'l')} />
          <div className="handle middle-right" onMouseDown={(e) => handleResizeStart(e, 'r')} />
        </div>
      )}
    </div>
  );
};

export default GeneratedComponent;
